#!/usr/bin/env python3
import base64, os

files = {
    '/home/ec2-user/ccs/ccs-react/vite.config.ts': '',
    '/home/ec2-user/ccs/ccs-react/src/lib/utils.ts': '',
}

for path, encoded in files.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        f.write(base64.b64decode(encoded).decode())
    print(f"✅ {path}")
print("\nNow restart vite: pkill -f vite && npm run dev")
